// // This module implements a 5-bit ring counter that starts with all bits set to '1' and shifts them right on each clock cycle.
module ring_counter(  
    input clk,  
    input rst,  
    output reg [4:0] count  
);  
    always @(posedge clk or posedge rst) begin  
        if (rst) begin  
            count <= 5'b00001;  
        end else begin  
            count <= {count[3:0], count[4]};  
        end  
    end  
endmodule
